+/// Verify the QE Identity signature against its certificate chain
+fn verify_qe_identity_signature(
+    qe_identity: &[u8],
+    signature: &[u8],
+    issuer_chain: &[u8],
+) -> Result<()> {
+    let certificate = parse_certificate(issuer_chain)?;
+    let root_cert = get_root_certificate()?;
+    
+    // Build and verify the certificate chain
+    let chain = CertificateChain::from_slice(issuer_chain)
+        .map_err(|_| VerifyError::InvalidCertificateChain)?;
+    
+    // Verify each certificate in the chain up to the root
+    chain.verify(&root_cert, qe_identity, signature)
+        .map_err(|_| VerifyError::InvalidQeIdentitySignature)?;
+    
+    Ok(())
